import numpy as np
import matplotlib.pyplot as plt


def parse_single_line_bits(s):
    s = s.strip()
    assert len(s) == 36 * 36, f"expect 1296 chars, got {len(s)}"
    arr = np.array([1.0 if ch == "1" else 0.0 for ch in s], dtype=np.float32)
    return arr.reshape(36, 36)


def visualize_binary_map(arr, title="map36"):
    plt.figure(figsize=(6, 6))
    plt.imshow(arr, cmap="gray", vmin=0.0, vmax=1.0, interpolation="nearest")
    plt.title(title)
    plt.colorbar()
    plt.tight_layout()
    plt.show()


if __name__ == "__main__":
    # 把 logger.warning 打出来的那一整串粘到这里
    s = ""
    
    arr = parse_single_line_bits(s)
    visualize_binary_map(arr, title="binary map 36x36")